# Helper functions
def get_breed_info(breed_name):
    """Get breed info with EXACT matching to model output"""
    # Direct exact match first
    if breed_name in BREED_DATABASE:
        return {"breed": breed_name, **BREED_DATABASE[breed_name]}
    
    # Fuzzy match as fallback
    name_lower = breed_name.lower().strip()
    for key in BREED_DATABASE:
        if key.lower() == name_lower:
            return {"breed": key, **BREED_DATABASE[key]}
    
    # Partial match
    for key in BREED_DATABASE:
        if name_lower in key.lower() or key.lower() in name_lower:
            return {"breed": key, **BREED_DATABASE[key]}
    
    return None

def get_all_breed_names():
    return sorted(BREED_DATABASE.keys())

def search_breeds(query):
    q = query.lower()
    return [name for name in BREED_DATABASE if q in name.lower()]

def get_breeds_by_india_suitability(min_score=70):
    result = []
    for name, data in BREED_DATABASE.items():
        score = data.get("india_suitability", {}).get("score", 50)
        if score >= min_score:
            result.append((name, score))
    return sorted(result, key=lambda x: x[1], reverse=True)

def get_breeds_suitable_for_apartments():
    return [n for n, d in BREED_DATABASE.items() if d.get("family_compatibility", {}).get("good_for_apartments")]

def get_breeds_for_beginners():
    return [n for n, d in BREED_DATABASE.items() if d.get("family_compatibility", {}).get("first_time_owner")]

if __name__ == "__main__":
    print(f"✅ Breed database: {len(BREED_DATABASE)} breeds")
    print("✅ EXACT MATCH to Stanford Dogs model output names")
    print("\n📋 Sample breeds from model:")
    samples = ["Affenpinscher", "Maltese Dog", "Golden Retriever", "Beagle", "German Shepherd", "Labrador Retriever", "Rajapalayam dog"]
    for s in samples:
        info = get_breed_info(s)
        if info:
            has_temp = "temperature" in info
            has_food = "food" in info
            print(f"  ✓ {s} → Found (temp={has_temp}, food={has_food})")
        else:
            print(f"  ✗ {s} → NOT FOUND")